# Category: datastore_security

import os
import sys
import getpass
import mysql.connector
from mysql.connector import errorcode

def prompt(msg, default=None, secret=False):
    if default is not None:
        msg = f"{msg} [{default}]: "
    else:
        msg = f"{msg}: "
    if secret:
        val = getpass.getpass(msg)
    else:
        val = input(msg)
    if not val and default is not None:
        return default
    return val

def parse_file_list(raw):
    parts = [p.strip() for p in raw.split(",")]
    return [p for p in parts if p]

def ensure_file_exists(path):
    if not os.path.exists(path):
        raise FileNotFoundError(f"File not found: {path}")
    if not os.path.isfile(path):
        raise FileNotFoundError(f"Not a file: {path}")
    return os.path.abspath(path)

def sanitize_mysql_string_literal(s):
    return s.replace("\\", "\\\\").replace("'", "''")

def build_load_sql(file_path, table, columns=None, fields_term=",", enclosed_by=None, escaped_by="\\", lines_term="\n", ignore_lines=1, charset="utf8mb4"):
    fp = sanitize_mysql_string_literal(file_path)
    tbl = table.strip()
    cols = ""
    if columns:
        col_list = [c.strip() for c in columns.split(",") if c.strip()]
        if col_list:
            cols = " (" + ", ".join(col_list) + ")"
    fields = f"FIELDS TERMINATED BY '{sanitize_mysql_string_literal(fields_term)}' "
    if enclosed_by is not None and enclosed_by != "":
        fields += f"OPTIONALLY ENCLOSED BY '{sanitize_mysql_string_literal(enclosed_by)}' "
    if escaped_by is not None and escaped_by != "":
        fields += f"ESCAPED BY '{sanitize_mysql_string_literal(escaped_by)}' "
    lines = f"LINES TERMINATED BY '{sanitize_mysql_string_literal(lines_term)}' "
    ignore = f"IGNORE {int(ignore_lines)} LINES " if int(ignore_lines) > 0 else ""
    sql = (
        "LOAD DATA LOCAL INFILE '{fp}' "
        "INTO TABLE {tbl} "
        "CHARACTER SET {charset} "
        "{fields}"
        "{lines}"
        "{ignore}"
        "{cols}"
    ).format(
        fp=fp,
        tbl=tbl,
        charset=charset,
        fields=fields,
        lines=lines,
        ignore=ignore,
        cols=cols
    )
    return sql

def connect_mysql(host, port, user, password, database, allow_local_infile=True):
    conn = mysql.connector.connect(
        host=host,
        port=int(port),
        user=user,
        password=password,
        database=database,
        allow_local_infile=bool(allow_local_infile),
        autocommit=False,
    )
    cur = conn.cursor()
    cur.execute("SET SESSION local_infile = 1")
    cur.close()
    return conn

def main():
    host = prompt("MySQL host", "localhost")
    port = prompt("MySQL port", "3306")
    user = prompt("MySQL user", "root")
    password = prompt("MySQL password", secret=True)
    database = prompt("MySQL database")

    table = prompt("Target table (e.g. schema.table or table)")
    columns = prompt("Column list (comma-separated) (optional)", default="")
    fields_term = prompt("FIELDS TERMINATED BY", ",")
    enclosed_by = prompt("OPTIONALLY ENCLOSED BY (leave blank for none)", default="")
    escaped_by = prompt("ESCAPED BY", "\\")
    lines_term = prompt("LINES TERMINATED BY", "\\n")
    ignore_lines = prompt("IGNORE N LINES", "1")
    charset = prompt("CHARACTER SET", "utf8mb4")

    raw_files = prompt("Input file paths (comma-separated)")
    file_paths = [ensure_file_exists(p) for p in parse_file_list(raw_files)]
    if not file_paths:
        print("No files provided.", file=sys.stderr)
        sys.exit(2)

    try:
        conn = connect_mysql(host, port, user, password, database, allow_local_infile=True)
    except mysql.connector.Error as err:
        if err.errno == errorcode.ER_ACCESS_DENIED_ERROR:
            print("Access denied (check username/password).", file=sys.stderr)
        elif err.errno == errorcode.ER_BAD_DB_ERROR:
            print("Database does not exist.", file=sys.stderr)
        else:
            print(f"MySQL connection error: {err}", file=sys.stderr)
        sys.exit(1)

    try:
        cur = conn.cursor()
        for fp in file_paths:
            sql = build_load_sql(
                file_path=fp,
                table=table,
                columns=columns if columns.strip() else None,
                fields_term=fields_term.encode("utf-8").decode("unicode_escape"),
                enclosed_by=(enclosed_by.encode("utf-8").decode("unicode_escape") if enclosed_by != "" else None),
                escaped_by=escaped_by.encode("utf-8").decode("unicode_escape"),
                lines_term=lines_term.encode("utf-8").decode("unicode_escape"),
                ignore_lines=int(ignore_lines),
                charset=charset.strip() or "utf8mb4",
            )
            cur.execute(sql)
            conn.commit()
            print(f"Imported: {fp}")
        cur.close()
    except mysql.connector.Error as err:
        conn.rollback()
        print(f"Import failed: {err}", file=sys.stderr)
        sys.exit(1)
    finally:
        conn.close()

if __name__ == "__main__":
    main()